CREATE TABLE "prompts" (
	"promptId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"title" varchar(255) NOT NULL,
	"common" text NOT NULL,
	"architecture" text NOT NULL,
	"code" text NOT NULL,
	"security" text NOT NULL,
	"tests" text NOT NULL,
	"operability" text NOT NULL,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"statusId" integer NOT NULL,
	CONSTRAINT "prompts_pkey" PRIMARY KEY("promptId")
);

CREATE TABLE "statuses" (
	"statusId" integer NOT NULL,
	"title" varchar(255) NOT NULL,
	"alias" varchar(64),
	CONSTRAINT "statuses_pkey" PRIMARY KEY("statusId")
);

CREATE TABLE "taskTrackers" (
	"taskTrackerId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"title" varchar(255) NOT NULL,
	"url" varchar(255) NOT NULL,
	"authToken" varchar(255),
	"fetchPrompt" text NOT NULL,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"statusId" integer NOT NULL,
	CONSTRAINT "taskTrackers_pkey" PRIMARY KEY("taskTrackerId")
);

CREATE TABLE "slackChannels" (
	"slackChannelId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"title" varchar(255) NOT NULL,
	"channel" varchar(255) NOT NULL,
	"webhookURL" varchar(1024) NOT NULL,
	"statusId" integer NOT NULL,
	CONSTRAINT "slackChannels_pkey" PRIMARY KEY("slackChannelId")
);

CREATE TABLE "projects" (
	"projectId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"title" varchar(255) NOT NULL,
	"vcsURL" varchar(255) NOT NULL,
	"language" varchar(32) NOT NULL,
	"projectKey" uuid NOT NULL,
	"instructions" text,
	"promptId" integer NOT NULL,
	"taskTrackerId" integer,
	"slackChannelId" integer,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"statusId" integer NOT NULL,
	CONSTRAINT "projects_pkey" PRIMARY KEY("projectId"),
	CONSTRAINT "UNQ_projects_projectKey" UNIQUE("projectKey")
);

CREATE TABLE "reviews" (
	"reviewId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"projectId" integer NOT NULL,
	"title" varchar(255) NOT NULL,
	"description" varchar(2048) NOT NULL,
	"externalId" varchar(32) NOT NULL,
	"trafficLight" varchar(32) NOT NULL DEFAULT 'none',
	"commitHash" varchar(40) NOT NULL,
	"sourceBranch" varchar(255) NOT NULL,
	"targetBranch" varchar(255) NOT NULL,
	"author" varchar(255) NOT NULL,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"durationMS" integer NOT NULL DEFAULT 0,
	"modelInfo" jsonb NOT NULL DEFAULT '{}',
	"statusId" integer NOT NULL,
	"promptId" integer NOT NULL,
	CONSTRAINT "reviews_pkey" PRIMARY KEY("reviewId")
);

CREATE TABLE "reviewFiles" (
	"reviewFileId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"reviewId" integer NOT NULL,
	"reviewType" varchar(64) NOT NULL,
	"content" text NOT NULL,
	"issueStats" jsonb NOT NULL DEFAULT '{}',
	"trafficLight" varchar(32) NOT NULL,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"summary" varchar(2048) NOT NULL,
	"isAccepted" boolean NOT NULL DEFAULT false,
	"statusId" integer NOT NULL,
	CONSTRAINT "reviewFiles_pkey" PRIMARY KEY("reviewFileId")
);

CREATE TABLE "issues" (
	"issueId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"reviewFileId" integer NOT NULL,
	"issueType" varchar(32) NOT NULL,
	"reviewId" integer NOT NULL,
	"title" varchar(255) NOT NULL,
	"severity" varchar(16) NOT NULL,
	"description" text NOT NULL,
	"content" text NOT NULL,
	"file" varchar(255) NOT NULL,
	"lines" varchar(255) NOT NULL,
	"comment" varchar(255),
	"localId" varchar(16),
	"processedAt" timestamptz,
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"userId" integer,
	"statusId" integer NOT NULL,
	CONSTRAINT "issues_pkey" PRIMARY KEY("issueId")
);

CREATE TABLE "users" (
	"userId" integer NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"login" varchar(64) NOT NULL,
	"password" varchar(64) NOT NULL,
	"authKey" varchar(32),
	"createdAt" timestamptz NOT NULL DEFAULT now(),
	"lastActivityAt" timestamptz,
	"statusId" integer NOT NULL,
	CONSTRAINT "users_pkey" PRIMARY KEY("userId")
);

CREATE INDEX "IX_reviews_projectId" ON "reviews" (
	"projectId"
);

